import { useState, useEffect } from 'react';

export function useHistory() {
  const [history, setHistory] = useState(() => {
    try {
      return JSON.parse(localStorage.getItem('disease-history') || '[]');
    } catch { return []; }
  });

  useEffect(() => {
    localStorage.setItem('disease-history', JSON.stringify(history));
  }, [history]);

  const addToHistory = (disease) => {
    setHistory(prev => {
      const filtered = prev.filter(item => item.id !== disease.id);
      const updated = [{ id: disease.id, name: disease.name, icd: disease.icd, timestamp: Date.now() }, ...filtered].slice(0, 10);
      return updated;
    });
  };

  const clearHistory = () => setHistory([]);

  return { history, addToHistory, clearHistory };
}
