import { useState, useEffect } from 'react';

export function useFavorites() {
  const [favorites, setFavorites] = useState(() => {
    try {
      return JSON.parse(localStorage.getItem('disease-favorites') || '[]');
    } catch { return []; }
  });

  useEffect(() => {
    localStorage.setItem('disease-favorites', JSON.stringify(favorites));
  }, [favorites]);

  const addFavorite = (diseaseId) => {
    if (!favorites.includes(diseaseId)) {
      setFavorites(prev => [...prev, diseaseId]);
    }
  };

  const removeFavorite = (diseaseId) => {
    setFavorites(prev => prev.filter(id => id !== diseaseId));
  };

  const toggleFavorite = (diseaseId) => {
    if (favorites.includes(diseaseId)) {
      removeFavorite(diseaseId);
    } else {
      addFavorite(diseaseId);
    }
  };

  const isFavorite = (diseaseId) => favorites.includes(diseaseId);

  return { favorites, addFavorite, removeFavorite, toggleFavorite, isFavorite };
}
